
-- =====================================================
-- RETRO GARAGE - Base completa con bastantes datos Costa Rica
-- SQL Server
-- Personas y datos personales: ficticios para pruebas académicas.
-- Fechas históricas incluidas: enero, febrero, marzo, abril, mayo y junio de 2026.
-- =====================================================

USE master;
GO

IF DB_ID(N'RetroGarage') IS NULL
BEGIN
    CREATE DATABASE RetroGarage;
END
GO

USE RetroGarage;
GO

-- Limpiar estructura anterior, si existe
IF OBJECT_ID(N'dbo.movimientos_inventario', N'U') IS NOT NULL DROP TABLE dbo.movimientos_inventario;
IF OBJECT_ID(N'dbo.pagos', N'U') IS NOT NULL DROP TABLE dbo.pagos;
IF OBJECT_ID(N'dbo.recuperacion_contrasena', N'U') IS NOT NULL DROP TABLE dbo.recuperacion_contrasena;
IF OBJECT_ID(N'dbo.sesiones_usuario', N'U') IS NOT NULL DROP TABLE dbo.sesiones_usuario;
IF OBJECT_ID(N'dbo.citas', N'U') IS NOT NULL DROP TABLE dbo.citas;
IF OBJECT_ID(N'dbo.productos', N'U') IS NOT NULL DROP TABLE dbo.productos;
IF OBJECT_ID(N'dbo.servicios', N'U') IS NOT NULL DROP TABLE dbo.servicios;
IF OBJECT_ID(N'dbo.usuarios', N'U') IS NOT NULL DROP TABLE dbo.usuarios;
IF OBJECT_ID(N'dbo.clientes', N'U') IS NOT NULL DROP TABLE dbo.clientes;
IF OBJECT_ID(N'dbo.categorias', N'U') IS NOT NULL DROP TABLE dbo.categorias;
IF OBJECT_ID(N'dbo.metodos_pago', N'U') IS NOT NULL DROP TABLE dbo.metodos_pago;
IF OBJECT_ID(N'dbo.roles', N'U') IS NOT NULL DROP TABLE dbo.roles;
GO

CREATE TABLE dbo.roles (
    id_rol          INT IDENTITY(1,1) PRIMARY KEY,
    nombre          NVARCHAR(50)  NOT NULL,
    descripcion     NVARCHAR(200) NULL
);
GO

CREATE TABLE dbo.usuarios (
    id_usuario      INT IDENTITY(1,1) PRIMARY KEY,
    id_rol          INT           NOT NULL,
    nombre_completo NVARCHAR(100) NOT NULL,
    correo          NVARCHAR(100) NOT NULL UNIQUE,
    telefono        NVARCHAR(20)  NULL,
    contrasena_hash NVARCHAR(255) NOT NULL,
    activo          BIT           NOT NULL DEFAULT 1,
    fecha_creacion  DATETIME      NOT NULL DEFAULT GETDATE(),
    ultimo_acceso   DATETIME      NULL,
    CONSTRAINT FK_usuarios_rol FOREIGN KEY (id_rol) REFERENCES dbo.roles(id_rol)
);
GO

CREATE TABLE dbo.sesiones_usuario (
    id_sesion           INT IDENTITY(1,1) PRIMARY KEY,
    id_usuario          INT           NOT NULL,
    token_sesion        NVARCHAR(500) NOT NULL UNIQUE,
    ip_origen           NVARCHAR(50)  NULL,
    fecha_inicio        DATETIME      NOT NULL DEFAULT GETDATE(),
    fecha_expiracion    DATETIME      NOT NULL,
    activa              BIT           NOT NULL DEFAULT 1,
    CONSTRAINT FK_sesiones_usuario FOREIGN KEY (id_usuario) REFERENCES dbo.usuarios(id_usuario)
);
GO

CREATE TABLE dbo.recuperacion_contrasena (
    id_recuperacion     INT IDENTITY(1,1) PRIMARY KEY,
    id_usuario          INT           NOT NULL,
    codigo_hash         NVARCHAR(255) NOT NULL,
    fecha_expiracion    DATETIME      NOT NULL,
    usado               BIT           NOT NULL DEFAULT 0,
    ip_solicitud        NVARCHAR(50)  NULL,
    fecha_solicitud     DATETIME      NOT NULL DEFAULT GETDATE(),
    CONSTRAINT FK_recuperacion_usuario FOREIGN KEY (id_usuario) REFERENCES dbo.usuarios(id_usuario)
);
GO

CREATE TABLE dbo.clientes (
    id_cliente          INT IDENTITY(1,1) PRIMARY KEY,
    nombre              NVARCHAR(100) NOT NULL,
    apellido            NVARCHAR(100) NOT NULL,
    identificacion      NVARCHAR(20)  NOT NULL UNIQUE,
    fecha_nacimiento    DATE          NULL,
    correo              NVARCHAR(100) NULL,
    telefono            NVARCHAR(20)  NOT NULL,
    provincia           NVARCHAR(100) NULL,
    canton              NVARCHAR(100) NULL,
    notas               NVARCHAR(500) NULL,
    activo              BIT           NOT NULL DEFAULT 1,
    fecha_registro      DATETIME      NOT NULL DEFAULT GETDATE()
);
GO

CREATE TABLE dbo.categorias (
    id_categoria    INT IDENTITY(1,1) PRIMARY KEY,
    nombre          NVARCHAR(100) NOT NULL,
    tipo            NVARCHAR(20)  NOT NULL,
    descripcion     NVARCHAR(300) NULL,
    activo          BIT           NOT NULL DEFAULT 1
);
GO

CREATE TABLE dbo.servicios (
    id_servicio         INT IDENTITY(1,1) PRIMARY KEY,
    id_categoria        INT             NOT NULL,
    nombre              NVARCHAR(150)   NOT NULL,
    precio_base         DECIMAL(10,2)   NOT NULL DEFAULT 0,
    activo              BIT             NOT NULL DEFAULT 1,
    CONSTRAINT FK_servicios_categoria FOREIGN KEY (id_categoria) REFERENCES dbo.categorias(id_categoria)
);
GO

CREATE TABLE dbo.productos (
    id_producto         INT IDENTITY(1,1) PRIMARY KEY,
    id_categoria        INT             NOT NULL,
    nombre              NVARCHAR(150)   NOT NULL,
    codigo_item         NVARCHAR(50)    NOT NULL UNIQUE,
    precio_venta        DECIMAL(10,2)   NOT NULL DEFAULT 0,
    precio_costo        DECIMAL(10,2)   NOT NULL DEFAULT 0,
    stock_actual        INT             NOT NULL DEFAULT 0,
    stock_minimo        INT             NOT NULL DEFAULT 0,
    unidad_medida       NVARCHAR(20)    NOT NULL DEFAULT 'Unidades',
    proveedor           NVARCHAR(150)   NULL,
    activo              BIT             NOT NULL DEFAULT 1,
    CONSTRAINT FK_productos_categoria FOREIGN KEY (id_categoria) REFERENCES dbo.categorias(id_categoria)
);
GO

CREATE TABLE dbo.citas (
    id_cita                 INT IDENTITY(1,1) PRIMARY KEY,
    id_cliente              INT             NOT NULL,
    id_servicio             INT             NOT NULL,
    marca_vehiculo          NVARCHAR(100)   NOT NULL,
    modelo_vehiculo         NVARCHAR(100)   NOT NULL,
    anio_vehiculo           INT             NULL,
    fecha                   DATE            NOT NULL,
    hora                    TIME            NOT NULL,
    descripcion             NVARCHAR(500)   NULL,
    estado                  NVARCHAR(20)    NOT NULL DEFAULT 'PENDIENTE',
    fecha_registro          DATETIME        NOT NULL DEFAULT GETDATE(),
    CONSTRAINT FK_citas_cliente  FOREIGN KEY (id_cliente)  REFERENCES dbo.clientes(id_cliente),
    CONSTRAINT FK_citas_servicio FOREIGN KEY (id_servicio) REFERENCES dbo.servicios(id_servicio)
);
GO

CREATE TABLE dbo.metodos_pago (
    id_metodo               INT IDENTITY(1,1) PRIMARY KEY,
    nombre                  NVARCHAR(50)  NOT NULL,
    requiere_referencia     BIT           NOT NULL DEFAULT 0,
    activo                  BIT           NOT NULL DEFAULT 1
);
GO

CREATE TABLE dbo.pagos (
    id_pago             INT IDENTITY(1,1) PRIMARY KEY,
    numero_factura      NVARCHAR(20)    NOT NULL UNIQUE,
    id_cita             INT             NOT NULL,
    id_usuario          INT             NOT NULL,
    id_metodo           INT             NOT NULL,
    monto               DECIMAL(10,2)   NOT NULL,
    monto_recibido      DECIMAL(10,2)   NULL,
    cambio              DECIMAL(10,2)   NULL,
    numero_referencia   NVARCHAR(100)   NULL,
    banco               NVARCHAR(100)   NULL,
    observaciones       NVARCHAR(500)   NULL,
    estado_pago         NVARCHAR(20)    NOT NULL DEFAULT 'COMPLETADO',
    fecha_pago          DATETIME        NOT NULL DEFAULT GETDATE(),
    CONSTRAINT FK_pagos_cita    FOREIGN KEY (id_cita)    REFERENCES dbo.citas(id_cita),
    CONSTRAINT FK_pagos_usuario FOREIGN KEY (id_usuario) REFERENCES dbo.usuarios(id_usuario),
    CONSTRAINT FK_pagos_metodo  FOREIGN KEY (id_metodo)  REFERENCES dbo.metodos_pago(id_metodo)
);
GO

CREATE TABLE dbo.movimientos_inventario (
    id_movimiento       INT IDENTITY(1,1) PRIMARY KEY,
    id_producto         INT             NOT NULL,
    id_cita             INT             NULL,
    id_usuario          INT             NOT NULL,
    tipo                NVARCHAR(20)    NOT NULL,
    cantidad            INT             NOT NULL,
    stock_anterior      INT             NOT NULL,
    stock_resultante    INT             NOT NULL,
    motivo              NVARCHAR(300)   NULL,
    fecha               DATETIME        NOT NULL DEFAULT GETDATE(),
    CONSTRAINT FK_mov_producto FOREIGN KEY (id_producto) REFERENCES dbo.productos(id_producto),
    CONSTRAINT FK_mov_cita     FOREIGN KEY (id_cita)     REFERENCES dbo.citas(id_cita),
    CONSTRAINT FK_mov_usuario  FOREIGN KEY (id_usuario)  REFERENCES dbo.usuarios(id_usuario)
);
GO

