-- =====================================================
-- RESUMEN DE CARGA
-- =====================================================
PRINT 'Base RetroGarage reconstruida y poblada correctamente.';
PRINT 'Registros cargados:';
SELECT 'roles' AS tabla, COUNT(*) AS registros FROM dbo.roles
UNION ALL SELECT 'metodos_pago', COUNT(*) FROM dbo.metodos_pago
UNION ALL SELECT 'categorias', COUNT(*) FROM dbo.categorias
UNION ALL SELECT 'usuarios', COUNT(*) FROM dbo.usuarios
UNION ALL SELECT 'clientes', COUNT(*) FROM dbo.clientes
UNION ALL SELECT 'servicios', COUNT(*) FROM dbo.servicios
UNION ALL SELECT 'productos', COUNT(*) FROM dbo.productos
UNION ALL SELECT 'sesiones_usuario', COUNT(*) FROM dbo.sesiones_usuario
UNION ALL SELECT 'recuperacion_contrasena', COUNT(*) FROM dbo.recuperacion_contrasena
UNION ALL SELECT 'citas', COUNT(*) FROM dbo.citas
UNION ALL SELECT 'pagos', COUNT(*) FROM dbo.pagos
UNION ALL SELECT 'movimientos_inventario', COUNT(*) FROM dbo.movimientos_inventario;
GO
